@app.route('/api/demo/full-auth-flow', methods=['POST'])
def demo_full_auth_flow():
    """
    Demo endpoint: Run through the complete authentication flow automatically.
    """
    # Create a new account
    account = w3.eth.account.create()
    address = account.address

    # Step 1: Generate nonce
    nonce = auth_service.generate_nonce(address)
    message = auth_service.build_sign_message(address, nonce)

    # Step 2: Sign the message
    message_encoded = encode_defunct(text=message)
    signed_message = w3.eth.account.sign_message(message_encoded, private_key=account.key)

    # Step 3: Verify
    recovered = auth_service.recover_address(message, signed_message.signature.hex())
    is_valid = recovered and recovered.lower() == address.lower()

    if is_valid:
        auth_service.invalidate_nonce(address)
        user = auth_service.get_or_create_user(address)
        token = auth_service.generate_jwt(address)

        return jsonify({
            'success': True,
            'flow': {
                'step1_nonce': nonce,
                'step2_message': message,
                'step3_signature': signed_message.signature.hex(),
                'step4_recovered_address': recovered,
                'step5_match': is_valid
            },
            'result': {
                'authenticated': True,
                'address': address,
                'token': token,
                'user': user
            }
        }), 200
    else:
        return jsonify({
            'success': False,
            'error': 'Authentication flow failed'
        }), 500


